companion object {
    fun fromDomain(concept: Concept): ConceptJpaEntity {
        val entity = ConceptJpaEntity(
            id = concept.id,
            conceptId = concept.conceptId,
            name = concept.name,
            category = concept.category.name,
            level = concept.level.name,
            description = concept.description
        )
        concept.synonyms.forEach { synonym ->
            entity.synonyms.add(ConceptSynonymJpaEntity(synonym = synonym, concept = entity))
        }
        return entity
    }
}

@Configuration
class OpenSearchConfig(
    @Value("\${opensearch.host}") private val host: String,
    @Value("\${opensearch.port}") private val port: Int,
    @Value("\${opensearch.scheme}") private val scheme: String
) {
    @Bean
    fun openSearchClient(): OpenSearchClient {
        val httpHost = HttpHost(scheme, host, port)
        val transport = ApacheHttpClient5TransportBuilder
            .builder(httpHost).setMapper(JacksonJsonpMapper()).build()
        return OpenSearchClient(transport)
    }
}

