@Service
class SearchService(private val searchPort: ConceptSearchPort) {
    fun search(command: SearchCommand): SearchResultDto {
        val response = searchPort.search(
            query = command.query,
            category = command.category,
            level = command.level,
            from = command.page * command.size,
            size = command.size
        )
        return SearchResultDto(hits = response.hits.map { ... }, totalHits = response.totalHits)
    }
}

